    "solution": "CREATE TABLE sanpham (MaSP CHAR(6) PRIMARY KEY, TenSP VARCHAR(128), DonGia REAL);\nCREATE TABLE khachhang (MaKH CHAR(8) PRIMARY KEY, TenKH VARCHAR(64));\nCREATE TABLE hoadon (MaHD CHAR(8) PRIMARY KEY, MaKH CHAR(8), NgayMua DATE,\n    FOREIGN KEY (MaKH) REFERENCES khachhang(MaKH));\nCREATE TABLE chitiet_hoadon (MaHD CHAR(8), MaSP CHAR(6), SoLuong INTEGER,\n    PRIMARY KEY (MaHD, MaSP),\n    FOREIGN KEY (MaHD) REFERENCES hoadon(MaHD),\n    FOREIGN KEY (MaSP) REFERENCES sanpham(MaSP));\n-- SELECT 1: Tất cả sản phẩm\nSELECT * FROM sanpham ORDER BY DonGia DESC;\n-- SELECT 2: Hóa đơn với tên khách\nSELECT h.MaHD, k.TenKH, h.NgayMua FROM hoadon h JOIN khachhang k ON h.MaKH = k.MaKH;",
