    "desc": "<b>Đề bài:</b> Viết SQL <b>DDL đầy đủ</b> để tạo CSDL âm nhạc gồm 4 bảng như trong SGK:\n<br>nhacsi (Aid, TenNS), bannhac (Mid, Aid, TenBN), casi (Sid, TenCS), banthuam (Mid, Sid).\n<br>Thêm đủ <b>khóa chính và khóa ngoại</b>. Thêm ít nhất <b>2 nhạc sĩ, 3 bản nhạc</b>.",
    "solution": "CREATE TABLE nhacsi (Aid INTEGER PRIMARY KEY, TenNS VARCHAR(64) NOT NULL);\nCREATE TABLE bannhac (Mid CHAR(4) PRIMARY KEY, Aid INTEGER, TenBN VARCHAR(128),\n    FOREIGN KEY (Aid) REFERENCES nhacsi(Aid));\nCREATE TABLE casi (Sid CHAR(4) PRIMARY KEY, TenCS VARCHAR(64) NOT NULL);\nCREATE TABLE banthuam (Mid CHAR(4), Sid CHAR(4), PRIMARY KEY (Mid, Sid),\n    FOREIGN KEY (Mid) REFERENCES bannhac(Mid),\n    FOREIGN KEY (Sid) REFERENCES casi(Sid));\nINSERT INTO nhacsi VALUES (1,'Trịnh Công Sơn'),(2,'Văn Cao');\nINSERT INTO bannhac VALUES ('0001',1,'Diễm xưa'),('0002',2,'Tiến về Hà Nội'),('0003',1,'Nối vòng tay lớn');",
    "theory": "<b>SQL – Structured Query Language</b><br>\nSQL có 3 thành phần chính:<br>\n<b>DDL</b> – Data Definition Language (Định nghĩa dữ liệu)<br>\n<b>DML</b> – Data Manipulation Language (Thao tác dữ liệu)<br>\n<b>DCL</b> – Data Control Language (Kiểm soát quyền truy cập)<br>\n<pre class=\"ex-code\">-- DDL: Tạo/sửa cấu trúc\nCREATE DATABASE ten_csdl;\nCREATE TABLE ten_bang (\n    cot1 KIEU_DU_LIEU PRIMARY KEY,\n    cot2 KIEU_DU_LIEU\n);\nALTER TABLE bang ADD PRIMARY KEY (cot);\nALTER TABLE bang ADD FOREIGN KEY (cot) REFERENCES bang2(cot2);\n\n-- DML: Thao tác dữ liệu\nSELECT ... FROM ... WHERE ... ORDER BY ...\nINSERT INTO bang VALUES (gt1, gt2, ...);\nDELETE FROM bang WHERE dieu_kien;\nUPDATE bang SET cot = gia_tri WHERE dieu_kien;\n\n-- DCL: Phân quyền\nGRANT quyen ON bang TO nguoi_dung;\nREVOKE quyen ON bang FROM nguoi_dung;</pre>\n<b>Kiểu dữ liệu SQL thường dùng:</b>\n<pre class=\"ex-code\">CHAR(n)     -- Chuỗi độ dài cố định n\nVARCHAR(n)  -- Chuỗi độ dài thay đổi, tối đa n\nINTEGER     -- Số nguyên\nREAL        -- Số thực\nDATE        -- Ngày (YYYY-MM-DD)\nBOOLEAN     -- True/False</pre>",
    "pseudo": "<pre class=\"ex-code\">## B6 – Sáng tạo / Thiết kế\nPHÂN TÍCH bài toán thực tế\nTHIẾT KẾ bảng (DDL)\nVIẾT SQL đầy đủ (INSERT + SELECT)\nKIỂM TRA tính nhất quán</pre>",
    "sample_db": "-- ════════════════════════════════\n--  CSDL ÂM NHẠC  (music) - KNTT Tin 11\n-- ════════════════════════════════\nCREATE TABLE nhacsi (\n    Aid   INTEGER PRIMARY KEY,\n    TenNS VARCHAR(64) NOT NULL\n);\nCREATE TABLE bannhac (\n    Mid  CHAR(4) PRIMARY KEY,\n    Aid  INTEGER NOT NULL,\n    TenBN VARCHAR(128),\n    FOREIGN KEY (Aid) REFERENCES nhacsi(Aid)\n);\nCREATE TABLE casi (\n    Sid  CHAR(4) PRIMARY KEY,\n    TenCS VARCHAR(64) NOT NULL\n);\nCREATE TABLE banthuam (\n    Mid CHAR(4),\n    Sid CHAR(4),\n    PRIMARY KEY (Mid, Sid),\n    FOREIGN KEY (Mid) REFERENCES bannhac(Mid),\n    FOREIGN KEY (Sid) REFERENCES casi(Sid)\n);\n\n-- Dữ liệu mẫu\nINSERT INTO nhacsi VALUES\n  (1,'Trịnh Công Sơn'),(2,'Văn Cao'),\n  (3,'Phú Quang'),(4,'Ngô Thụy Miên'),(5,'Hoàng Hiệp');\nINSERT INTO bannhac VALUES\n  ('0001',1,'Nối vòng tay lớn'),('0002',1,'Diễm xưa'),\n  ('0003',2,'Tiến về Hà Nội'),('0004',2,'Mùa xuân đầu tiên'),\n  ('0005',3,'Em ơi Hà Nội phố'),('0006',4,'Mắt biếc'),\n  ('0007',3,'Về thăm quê');\nINSERT INTO casi VALUES\n  ('TK','Trung Kiên'),('QD','Quý Dương'),\n  ('YM','Y Moan'),('MT','Mỹ Tâm'),('TH','Tuấn Hưng');\nINSERT INTO banthuam VALUES\n  ('0001','TK'),('0001','QD'),('0002','YM'),\n  ('0003','TK'),('0004','MT'),('0005','YM'),\n  ('0006','MT'),('0007','TH'),('0002','TK');\n\n-- ════════════════════════════════\n--  CSDL TRƯỜNG HỌC  (truong)\n-- ════════════════════════════════\nCREATE TABLE lophoc (\n    MaLop CHAR(6) PRIMARY KEY,\n    TenLop VARCHAR(20),\n    GVChuNhiem VARCHAR(64)\n);\nCREATE TABLE hocsinh (\n    MaHS  CHAR(8) PRIMARY KEY,\n    HoTen VARCHAR(64) NOT NULL,\n    NgaySinh DATE,\n    MaLop CHAR(6),\n    FOREIGN KEY (MaLop) REFERENCES lophoc(MaLop)\n);\nCREATE TABLE monhoc (\n    MaMon CHAR(4) PRIMARY KEY,\n    TenMon VARCHAR(64),\n    SoTiet INTEGER\n);\nCREATE TABLE diem (\n    MaHS  CHAR(8),\n    MaMon CHAR(4),\n    DiemGiuaKy REAL,\n    DiemCuoiKy REAL,\n    PRIMARY KEY (MaHS, MaMon)\n);\nINSERT INTO lophoc VALUES\n  ('11A1','Lớp 11A1','Nguyễn Thị Lan'),\n  ('11A2','Lớp 11A2','Trần Văn Minh'),\n  ('11A3','Lớp 11A3','Lê Thị Hoa');\nINSERT INTO hocsinh VALUES\n  ('HS240001','Nguyễn Văn An','2007-05-12','11A1'),\n  ('HS240002','Trần Thị Bình','2007-03-22','11A1'),\n  ('HS240003','Lê Văn Cường','2007-08-15','11A2'),\n  ('HS240004','Phạm Thị Dung','2007-01-30','11A2'),\n  ('HS240005','Hoàng Văn Em','2007-11-05','11A1'),\n  ('HS240006','Ngô Thị Phương','2007-06-18','11A3');\nINSERT INTO monhoc VALUES\n  ('TOAN','Toán',5),('LY','Vật Lý',3),\n  ('HOA','Hóa Học',3),('TIN','Tin Học',2),('VAN','Ngữ Văn',4);\nINSERT INTO diem VALUES\n  ('HS240001','TOAN',8.5,9.0),('HS240001','LY',7.0,8.0),\n  ('HS240001','TIN',9.0,9.5),('HS240002','TOAN',6.5,7.0),\n  ('HS240002','VAN',8.0,8.5),('HS240003','TOAN',5.0,6.0),\n  ('HS240003','HOA',7.5,8.0),('HS240004','LY',4.5,5.5),\n  ('HS240005','TOAN',9.5,10.0),('HS240005','TIN',10.0,10.0);",
