    "solution": "CREATE TABLE tacgias (MaTG CHAR(4) PRIMARY KEY, TenTG VARCHAR(64), QuocTich VARCHAR(32));\nCREATE TABLE sachs (MaSach CHAR(6) PRIMARY KEY, TenSach VARCHAR(128), NamXB INTEGER, MaTG CHAR(4),\n    FOREIGN KEY (MaTG) REFERENCES tacgias(MaTG));\nCREATE TABLE muontra (MaPhieu CHAR(8) PRIMARY KEY, MaHS CHAR(8), MaSach CHAR(6),\n    NgayMuon DATE, HanTra DATE,\n    FOREIGN KEY (MaSach) REFERENCES sachs(MaSach));\nINSERT INTO tacgias VALUES ('TG01','Nguyễn Nhật Ánh','Việt Nam');\nINSERT INTO sachs VALUES ('S0001','Tôi thấy hoa vàng trên cỏ xanh',2010,'TG01');\nINSERT INTO sachs VALUES ('S0002','Cho tôi xin một vé đi tuổi thơ',2008,'TG01');\nINSERT INTO sachs VALUES ('S0003','Mắt biếc',1990,'TG01');",
